# OEIS sequence: A025487

from heapq import heappop, heappush
from sympy import prevprime, nextprime, factorint
def A025487_gen(): # generator of terms if first n terms of sequence is desired
    h, hset = [1], {1}
    while True:
        yield (m:=heappop(h))
        ps = factorint(m)
        for p in ps:
            if p == 2 or ps[prevprime(p)]>ps[p]:
                mp = m*p
                if mp not in hset:
                    heappush(h,mp)
                    hset.add(mp)
        mp = m*nextprime(max(ps.keys(),default=1))
        if mp not in hset:
            heappush(h,mp)
            hset.add(mp)
A025487_list = list(islice(A025487_gen(),40)) # _Chai Wah Wu_, Mar 21 2026

